import { useEffect, useLayoutEffect, useMemo, useRef, useState } from "react";
import { useQuery, useQueries, useMutation, useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";
import api from "@/api/app/client";
import { getApiErrorMessage } from "@/api/app/apiError";
import {
  Plus,
  Edit2,
  Trash2,
  Globe,
  Building2,
  Mail,
  CreditCard,
  Briefcase,
  MapPin,
  Loader2,
  FileText,
} from "lucide-react";
import { HarmonyTable, type HarmonyColumn } from '@/components/ui/harmony-table';
import { HarmonyProfilePictureUploader } from '@/components/ui/harmony-profile-picture-uploader';
import HarmonyRichText from '@/components/ui/harmony-richtext';
import { CustomerFormDialog } from "@/features/customers/components/CustomerFormDialog";
import { HarmonyAlertDialog } from "@/components/ui/harmony-alert-dialog";
import { PermissionGate } from "@/components/shared/PermissionGate";
import { PERMISSIONS } from "@/constants/permissions";
import { Button } from "@/shadcn/components/ui/button";
import { Badge } from '@/shadcn/components/ui/badge';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/shadcn/components/ui/tooltip";
import { getAuthorizedFileUrl, cleanupBlobUrl } from "@/utils/fileUtils";
import { formatDate } from "@/utils/dateUtils";
import { safeExternalHref } from "@/utils/urlUtils";
import { uploadService } from "@/api/uploadService";
import { queryKeys } from '@/lib/queryKeys';
import type { Customer } from "@/types/customer";
import type { Project } from "@/types/project";
import { ProjectStatus } from "@/types/enums";

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const extractList = (res: any): any[] => {
  const data = res?.data || res?.items || res;
  return Array.isArray(data) ? data : [];
};

const buildCustomerPayload = (data: Record<string, unknown>, isEditMode: boolean, editData: Customer | null) => {
  const raw = {
    ...data,
    LogoFileId: isEditMode && editData ? (editData as Customer).logoFileId : (data.LogoFileId || null),
  };
  const payload: Record<string, unknown> = {};
  Object.keys(raw).forEach(key => { if (key[0] === key[0].toUpperCase()) payload[key] = (raw as Record<string, unknown>)[key]; });
  return payload;
};

const buildProjectPayload = (data: Record<string, unknown>, isEditMode: boolean, editData: Project | null, selectedCustomerId: string) => {
  const raw = {
    ...data,
    CustomerId: isEditMode ? (editData as Project).customerId : selectedCustomerId,
  };
  const payload: Record<string, unknown> = {};
  Object.keys(raw).forEach(key => { if (key[0] === key[0].toUpperCase()) payload[key] = (raw as Record<string, unknown>)[key]; });
  return payload;
};

const Customers = () => {
  const queryClient = useQueryClient();

  const [logoBlobUrls, setLogoBlobUrls] = useState<Record<string, { url: string; fileId: string }>>({});
  const logoBlobUrlsRef = useRef(logoBlobUrls);
  useLayoutEffect(() => { logoBlobUrlsRef.current = logoBlobUrls; });
  const [showForm, setShowForm] = useState(false);
  const [formType, setFormType] = useState<"CustomerDTO" | "ProjectDTO" | "">();
  const [selectedCustomerId, setSelectedCustomerId] = useState("");
  const [editData, setEditData] = useState<Customer | Project | null>(null);
  const [isEditMode, setIsEditMode] = useState(false);
  const [uploadingId, setUploadingId] = useState<string | null>(null);
  const [itemToDelete, setItemToDelete] = useState<{ id: string; name: string; type: "Customer" | "Project"; customerId?: string } | null>(null);

  // ── Queries ────────────────────────────────────────────────────────────────

  const { data: customers = [], isLoading } = useQuery<Customer[]>({
    queryKey: queryKeys.customers.all(),
    queryFn: () => api.get("/customers").then(r => extractList(r.data)),
  });

  const projectQueries = useQueries({
    queries: customers.map(c => ({
      queryKey: queryKeys.customers.projects(c.id),
      queryFn: () => api.get(`/customers/${c.id}/projects`).then(r => extractList(r.data) as Project[]),
    })),
  });

  const projectsMap = useMemo(() => {
    return customers.reduce((acc, c, i) => {
      acc[c.id] = projectQueries[i]?.data ?? [];
      return acc;
    }, {} as Record<string, Project[]>);
  }, [customers, projectQueries]);

  // ── Logo blob URL management (side effect, stays as local state) ───────────

  useEffect(() => {
    let isMounted = true;
    const fetchLogos = async () => {
      const updates: Record<string, { url: string; fileId: string }> = {};
      for (const c of customers) {
        if (!isMounted) break;
        if (c.logoFileId) {
          const current = logoBlobUrlsRef.current[c.id];
          if (!current || current.fileId !== c.logoFileId) {
            if (current?.url) cleanupBlobUrl(current.url);
            const blobUrl = await getAuthorizedFileUrl(c.logoFileId);
            if (!isMounted) {
              if (blobUrl) cleanupBlobUrl(blobUrl);
              break;
            }
            if (blobUrl) updates[c.id] = { url: blobUrl, fileId: c.logoFileId };
          }
        }
      }
      if (isMounted && Object.keys(updates).length > 0) {
        setLogoBlobUrls(prev => ({ ...prev, ...updates }));
      }
    };
    if (customers.length > 0) fetchLogos();
    return () => { isMounted = false; };
  }, [customers]);

  useEffect(() => {
    return () => { Object.values(logoBlobUrlsRef.current).forEach(item => cleanupBlobUrl(item.url)); };
  }, []);

  // ── Mutations ──────────────────────────────────────────────────────────────

  const createCustomerMutation = useMutation({
    mutationFn: (payload: Record<string, unknown>) => api.post("/customers", payload),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.customers.all() });
      setShowForm(false);
      toast.success("Customer created");
    },
    onError: (err) => toast.error(getApiErrorMessage(err, "Failed to create customer")),
  });

  const updateCustomerMutation = useMutation({
    mutationFn: ({ id, payload }: { id: string; payload: Record<string, unknown> }) =>
      api.put(`/customers/${id}`, payload),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.customers.all() });
      setShowForm(false);
      toast.success("Customer updated");
    },
    onError: (err) => toast.error(getApiErrorMessage(err, "Failed to update customer")),
  });

  const deleteCustomerMutation = useMutation({
    mutationFn: (id: string) => api.delete(`/customers/${id}`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.customers.all() });
      setItemToDelete(null);
      toast.success("Customer deleted");
    },
    onError: (err) => toast.error(getApiErrorMessage(err, "Delete failed")),
  });

  const createProjectMutation = useMutation({
    mutationFn: ({ customerId, payload }: { customerId: string; payload: Record<string, unknown> }) =>
      api.post("/projects", payload).then(() => customerId),
    onSuccess: (customerId) => {
      queryClient.invalidateQueries({ queryKey: queryKeys.customers.projects(customerId) });
      setShowForm(false);
      toast.success("Project created");
    },
    onError: (err) => toast.error(getApiErrorMessage(err, "Failed to create project")),
  });

  const updateProjectMutation = useMutation({
    mutationFn: ({ id, customerId, payload }: { id: string; customerId: string; payload: Record<string, unknown> }) =>
      api.put(`/projects/${id}`, payload).then(() => customerId),
    onSuccess: (customerId) => {
      queryClient.invalidateQueries({ queryKey: queryKeys.customers.projects(customerId) });
      setShowForm(false);
      toast.success("Project updated");
    },
    onError: (err) => toast.error(getApiErrorMessage(err, "Failed to update project")),
  });

  const deleteProjectMutation = useMutation({
    mutationFn: ({ id, customerId }: { id: string; customerId: string }) =>
      api.delete(`/projects/${id}`).then(() => customerId),
    onSuccess: (customerId) => {
      queryClient.invalidateQueries({ queryKey: queryKeys.customers.projects(customerId) });
      setItemToDelete(null);
      toast.success("Project deleted");
    },
    onError: (err) => toast.error(getApiErrorMessage(err, "Delete failed")),
  });

  // ── Handlers ───────────────────────────────────────────────────────────────

  const handleFormSubmit = (data: Record<string, unknown>) => {
    if (formType === "CustomerDTO") {
      const payload = buildCustomerPayload(data, isEditMode, editData as Customer | null);
      if (isEditMode && editData?.id) {
        updateCustomerMutation.mutate({ id: editData.id, payload });
      } else {
        createCustomerMutation.mutate(payload);
      }
    } else if (formType === "ProjectDTO") {
      const payload = buildProjectPayload(data, isEditMode, editData as Project | null, selectedCustomerId);
      if (isEditMode && editData?.id) {
        updateProjectMutation.mutate({ id: editData.id, customerId: payload.CustomerId as string, payload });
      } else {
        createProjectMutation.mutate({ customerId: payload.CustomerId as string, payload });
      }
    }
  };

  const handleDeleteItem = (id: string, name: string, type: "Customer" | "Project", customerId?: string) => {
    setItemToDelete({ id, name, type, customerId });
  };

  const confirmDelete = () => {
    if (!itemToDelete) return;
    if (itemToDelete.type === "Customer") {
      deleteCustomerMutation.mutate(itemToDelete.id);
    } else {
      deleteProjectMutation.mutate({ id: itemToDelete.id, customerId: itemToDelete.customerId! });
    }
  };

  const handleLogoUpload = async (customerId: string, file: File) => {
    setUploadingId(customerId);
    try {
      const uploadedFile = await uploadService.upload("/files", file);
      const customer = customers.find(c => c.id === customerId);
      if (!customer) return;

      const payload = {
        Name: customer.name,
        Website: customer.website,
        Industry: customer.industry,
        Notes: customer.notes,
        ContactsInfo: customer.contactsInfo,
        PaymentNotes: customer.paymentNotes,
        RegisteredAddress: customer.registeredAddress,
        IsActive: customer.isActive,
        LogoFileId: uploadedFile.id || uploadedFile,
      };

      await api.put(`/customers/${customerId}`, payload);
      queryClient.invalidateQueries({ queryKey: queryKeys.customers.all() });
      toast.success("Logo updated");
    } catch (err) {
      toast.error(getApiErrorMessage(err, "Upload failed"));
    } finally {
      setUploadingId(null);
    }
  };

  // ── Helpers ────────────────────────────────────────────────────────────────

  const getProjectStatusBadge = (status: ProjectStatus) => {
    if (status === ProjectStatus.Active) return <Badge variant="outline" className="bg-emerald-50 dark:bg-emerald-950/40 text-emerald-700 dark:text-emerald-400 border-emerald-200 dark:border-emerald-800 text-[10px] uppercase tracking-wider font-bold">Active</Badge>;
    if (status === ProjectStatus.OnHold) return <Badge variant="outline" className="bg-amber-50 dark:bg-amber-950/40 text-amber-700 dark:text-amber-400 border-amber-200 dark:border-amber-800 text-[10px] uppercase tracking-wider font-bold">On Hold</Badge>;
    if (status === ProjectStatus.Completed) return <Badge variant="outline" className="bg-primary/10 text-primary border-primary/20 text-[10px] uppercase tracking-wider font-bold">Completed</Badge>;
    if (status === ProjectStatus.Cancelled) return <Badge variant="destructive" className="text-[10px] uppercase tracking-wider font-bold">Cancelled</Badge>;
    return <Badge variant="secondary" className="text-[10px] uppercase tracking-wider font-bold">Planning</Badge>;
  };

  const projectColumns: HarmonyColumn<Project>[] = [
    {
      key: 'name',
      header: 'Project Name',
      fill: true,
      sortable: false,
      renderCell: ({ row }) => <span className="font-medium text-foreground">{row.name}</span>,
    },
    {
      key: 'code',
      header: 'Code',
      width: 110,
      sortable: false,
      renderCell: ({ row }) => row.code || '—',
    },
    {
      key: 'type',
      header: 'Type',
      width: 100,
      sortable: false,
      renderCell: ({ row }) => row.type || '—',
    },
    {
      key: 'status',
      header: 'Status',
      width: 100,
      sortable: false,
      renderCell: ({ row }) => getProjectStatusBadge(row.status),
    },
    {
      key: 'startDate',
      header: 'Start',
      width: 100,
      sortable: false,
      renderCell: ({ row }) => row.startDate ? formatDate(row.startDate) : '—',
    },
    {
      key: 'endDate',
      header: 'End',
      width: 100,
      sortable: false,
      renderCell: ({ row }) => row.endDate ? formatDate(row.endDate) : '—',
    },
    {
      key: 'actions',
      header: 'Actions',
      width: 80,
      sortable: false,
      resizable: false,
      cellClass: 'rdg-cell-actions',
      renderCell: ({ row }) => (
        <TooltipProvider>
          <div className="flex items-center gap-0.5">
            <PermissionGate permission={PERMISSIONS.Project.Update} mode="disable">
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    size="icon-xs"
                    variant="ghost"
                    className="text-muted-foreground hover:text-foreground"
                    onClick={(e) => { e.stopPropagation(); setFormType("ProjectDTO"); setSelectedCustomerId(row.customerId ?? ''); setIsEditMode(true); setEditData(row); setShowForm(true); }}
                  >
                    <Edit2 size={12} />
                  </Button>
                </TooltipTrigger>
                <TooltipContent>Edit Project</TooltipContent>
              </Tooltip>
            </PermissionGate>
            <PermissionGate permission={PERMISSIONS.Project.Delete} mode="disable">
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    size="icon-xs"
                    variant="ghost"
                    className="text-muted-foreground hover:text-destructive hover:bg-destructive/10"
                    onClick={(e) => { e.stopPropagation(); handleDeleteItem(row.id, row.name, "Project", row.customerId); }}
                  >
                    <Trash2 size={12} />
                  </Button>
                </TooltipTrigger>
                <TooltipContent>Delete Project</TooltipContent>
              </Tooltip>
            </PermissionGate>
          </div>
        </TooltipProvider>
      ),
    },
  ];

  const isFormSubmitting = createCustomerMutation.isPending || updateCustomerMutation.isPending
    || createProjectMutation.isPending || updateProjectMutation.isPending;

  const isDeleting = deleteCustomerMutation.isPending || deleteProjectMutation.isPending;

  // ── Render ─────────────────────────────────────────────────────────────────

  return (
    <div className="page-wrapper">
      <div className="page-header">
        <div className="flex items-center gap-3">
          <div className="size-12 flex items-center justify-center rounded-(--radius-lg) bg-primary/10 shrink-0">
            <Briefcase className="w-7 h-7 text-primary" />
          </div>
          <div>
            <h1 className="page-title">Customers &amp; Projects</h1>
            <p className="page-subtitle">Enterprise materials &amp; account registry</p>
          </div>
        </div>
        <PermissionGate permission={PERMISSIONS.Customer.Create} mode="disable">
          <Button onClick={() => { setFormType("CustomerDTO"); setIsEditMode(false); setEditData(null); setShowForm(true); }}>
            <Plus size={16} /> Add Customer
          </Button>
        </PermissionGate>
      </div>

      {isLoading && customers.length === 0 ? (
        <div className="flex justify-center py-20"><Loader2 className="w-8 h-8 animate-spin text-primary" /></div>
      ) : customers.length === 0 ? (
        <div className="text-center py-20 bg-card rounded-(--radius-lg) border border-border">
          <Building2 className="w-12 h-12 mx-auto text-muted-foreground/30 mb-4" />
          <h3 className="text-base font-semibold text-foreground">No Customers Found</h3>
          <p className="text-muted-foreground text-sm mt-1">Start by adding your first enterprise client.</p>
        </div>
      ) : (
        <div className="flex flex-col" style={{ gap: 'var(--section-padding)' }}>
          {customers.map((c) => (
            <div key={c.id} className="bg-card rounded-(--radius-lg) shadow-sm border border-border overflow-hidden">

              {/* ── Profile section (logo left, details right) ─────────────── */}
              <div className="flex flex-col sm:flex-row items-center gap-(--section-padding) p-6">

                {/* Logo */}
                <div className="shrink-0">
                  <HarmonyProfilePictureUploader
                    imageUrl={c.logoFileId && logoBlobUrls[c.id]?.url ? logoBlobUrls[c.id].url : null}
                    onFileSelected={(file) => handleLogoUpload(c.id, file)}
                    uploading={uploadingId === c.id}
                    shape="rounded"
                    size="lg"
                    fallback={<Building2 className="w-12 h-12 text-muted-foreground/30" />}
                  />
                </div>

                {/* Details */}
                <div className="flex-1 min-w-0">
                  <div className="flex justify-between items-start gap-4">
                    <div className="min-w-0">
                      <div className="flex items-center gap-3 flex-wrap">
                        <h2 className="text-lg font-bold text-foreground">{c.name}</h2>
                        <Badge variant="outline" className={c.isActive ? "bg-emerald-50 dark:bg-emerald-950/40 text-emerald-700 dark:text-emerald-400 border-emerald-200 dark:border-emerald-800" : "bg-destructive/10 text-destructive border-destructive/20"}>
                          {c.isActive ? "Active" : "Inactive"}
                        </Badge>
                      </div>
                      <div className="flex items-center gap-6 mt-2 flex-wrap">
                        {c.website && (
                          <a href={safeExternalHref(`https://${c.website}`)} target="_blank" rel="noreferrer" className="flex items-center gap-1.5 text-xs text-primary hover:underline">
                            <Globe size={13} /> {c.website}
                          </a>
                        )}
                        {c.industry && (
                          <span className="flex items-center gap-1.5 text-xs text-muted-foreground">
                            <Briefcase size={13} /> {c.industry}
                          </span>
                        )}
                      </div>

                      {c.notes && (
                        <div className="mt-5">
                          <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest flex items-center gap-2 mb-2">
                            <FileText size={12} /> Notes
                          </span>
                          <HarmonyRichText value={c.notes} onChange={() => {}} readOnly />
                        </div>
                      )}

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-5">
                        <div className="flex items-start gap-3">
                          <MapPin size={15} className="text-muted-foreground mt-0.5 shrink-0" />
                          <div className="text-xs font-bold text-muted-foreground leading-relaxed">
                            {c.registeredAddress ? (
                              <>
                                {c.registeredAddress.addressLine && <p className="text-foreground mb-0.5">{c.registeredAddress.addressLine}</p>}
                                <p>{c.registeredAddress.city}{c.registeredAddress.state && `, ${c.registeredAddress.state}`} {c.registeredAddress.zipCode}</p>
                                <p>{c.registeredAddress.country}</p>
                              </>
                            ) : "No address recorded"}
                          </div>
                        </div>
                        <div className="bg-muted/50 rounded-2xl p-4 space-y-4">
                          <div>
                            <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest flex items-center gap-2 mb-2">
                              <Mail size={12} /> Contacts
                            </span>
                            {c.contactsInfo
                              ? <HarmonyRichText value={c.contactsInfo} onChange={() => {}} readOnly />
                              : <span className="text-xs text-muted-foreground italic">N/A</span>
                            }
                          </div>
                          <div>
                            <span className="text-[10px] font-black text-muted-foreground uppercase tracking-widest flex items-center gap-2 mb-2">
                              <CreditCard size={12} /> Billing
                            </span>
                            {c.paymentNotes
                              ? <HarmonyRichText value={c.paymentNotes} onChange={() => {}} readOnly />
                              : <span className="text-xs text-muted-foreground italic">Standard</span>
                            }
                          </div>
                        </div>
                      </div>
                    </div>

                    {/* Edit / Delete */}
                    <TooltipProvider>
                      <div className="flex gap-1 shrink-0">
                        <PermissionGate permission={PERMISSIONS.Customer.Update} mode="disable">
                          <Tooltip>
                            <TooltipTrigger asChild>
                              <Button variant="ghost" size="icon-xs" className="text-muted-foreground hover:text-foreground" onClick={() => { setFormType("CustomerDTO"); setIsEditMode(true); setEditData(c); setShowForm(true); }}>
                                <Edit2 size={12} />
                              </Button>
                            </TooltipTrigger>
                            <TooltipContent>Edit Customer</TooltipContent>
                          </Tooltip>
                        </PermissionGate>
                        <PermissionGate permission={PERMISSIONS.Customer.Delete} mode="disable">
                          <Tooltip>
                            <TooltipTrigger asChild>
                              <Button variant="ghost" size="icon-xs" className="text-muted-foreground hover:text-destructive hover:bg-destructive/10" onClick={() => handleDeleteItem(c.id, c.name, "Customer")}>
                                <Trash2 size={12} />
                              </Button>
                            </TooltipTrigger>
                            <TooltipContent>Delete Customer</TooltipContent>
                          </Tooltip>
                        </PermissionGate>
                      </div>
                    </TooltipProvider>
                  </div>
                </div>
              </div>

              {/* ── Projects table inside the same card ───────────────────── */}
              <div className="border-t border-border" style={{ padding: 'var(--section-padding)' }}>
                <HarmonyTable<Project>
                  rows={projectsMap[c.id] ?? []}
                  columns={projectColumns}
                  rowKeyGetter={(row) => row.id}
                  loading={projectQueries[customers.indexOf(c)]?.isLoading ?? false}
                  searchPlaceholder="Search projects…"
                  emptyMessage="No projects found"
                  dataActions={{
                    extra: (
                      <PermissionGate permission={PERMISSIONS.Project.Create} mode="disable">
                        <Button size="sm" onClick={() => { setFormType("ProjectDTO"); setSelectedCustomerId(c.id); setIsEditMode(false); setEditData(null); setShowForm(true); }}>
                          <Plus size={14} /> New Project
                        </Button>
                      </PermissionGate>
                    ),
                  }}
                />
              </div>
            </div>
          ))}
        </div>
      )}

      <CustomerFormDialog
        open={showForm}
        onClose={() => setShowForm(false)}
        formType={formType ?? ""}
        isEditMode={isEditMode}
        editData={editData}
        onSubmit={handleFormSubmit}
        isSubmitting={isFormSubmitting}
      />

      {itemToDelete && (
        <HarmonyAlertDialog
          open={!!itemToDelete}
          onOpenChange={(open) => { if (!open) setItemToDelete(null); }}
          variant="danger"
          title={`Delete ${itemToDelete.type}`}
          description={`This will permanently remove "${itemToDelete.name}". This action cannot be undone.`}
          actionLabel="Permanently Delete"
          onAction={confirmDelete}
          isActioning={isDeleting}
        />
      )}
    </div>
  );
};

export default Customers;
